import{_ as e,c as n,a1 as a,o as c}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Ẩn File sử dụng NTFS Streams","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/8-NTFS-Streams.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/8-NTFS-Streams.md"}'),s={name:"vi/categories/ethical-hacking-labs/5-system-hacking/8-NTFS-Streams.md"};function i(r,t,o,h,l,g){return c(),n("div",null,t[0]||(t[0]=[a('<h1 id="an-file-su-dung-ntfs-streams" tabindex="-1">Ẩn File sử dụng NTFS Streams <a class="header-anchor" href="#an-file-su-dung-ntfs-streams" aria-label="Permalink to &quot;Ẩn File sử dụng NTFS Streams&quot;">​</a></h1><p>Một stream bao gồm dữ liệu liên kết với một thư mục file chính (được gọi là stream chính không tên). Mỗi file và thư mục trong NTFS có thể có nhiều luồng dữ liệu mà thường bị ẩn khỏi người dùng.</p><p><a href="https://docs.microsoft.com/en-us/sysinternals/downloads/streams" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/sysinternals/downloads/streams</a></p><p>NTFS thay thế hệ thống file FAT như là hệ thống file ưa thích cho hệ điều hành Microsoft Windows. NTFS có nhiều cải tiến so với FAT và HPFS (High Performance File System), như hỗ trợ tốt hơn cho metadata và sử dụng cấu trúc dữ liệu nâng cao.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Cách ẩn file sử dụng NTFS streams.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Windows 7, 8, 10 hoặc Windows Server 2012, 2016.</li></ul><h2 id="an-du-lieu-su-dung-ntfs-streams" tabindex="-1">Ẩn Dữ liệu sử dụng NTFS streams <a class="header-anchor" href="#an-du-lieu-su-dung-ntfs-streams" aria-label="Permalink to &quot;Ẩn Dữ liệu sử dụng NTFS streams&quot;">​</a></h2><p>Hãy chắc chắn hệ thống file ổ <strong>C:</strong> là định dạng <strong>NTFS</strong>. Để kiểm tra, vào <strong>Computer</strong> và nhấp chuột phải vào C:\\ rồi nhấp Properties.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/47c51699608fdb618bf4f38b8721c9cdb0ce7288/NTFS-1.png" alt="NFTS-Info-1"></p><ol><li><p>Mở Windows Explorer và tạo một <strong>thư mục mới</strong> tên <strong>trick</strong> bên trong ổ <strong>C:</strong>.</p></li><li><p>Truy cập <strong>C:\\windows\\system32</strong> và sao chép <strong>calc.exe</strong> vào thư mục <strong>trick</strong>. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b1b0f3cef708249202b1679f71d1acd2588ac6fa/NTFS-calc-copy2.png" alt="Calc-copy"></p></li><li><p>Khởi chạy <strong>command prompt</strong> với quyền Administrator, và điều hướng đến <strong>C:\\trick</strong>. <code>cd C:\\trick</code></p></li><li><p>Tạo file readme.txt, nhập Hello World vào bên trong và lưu file. <code>notepad readme.txt</code></p></li><li><p>Quay lại command prompt và nhập <strong>dir</strong> để liệt kê các file trong thư mục hiện tại. <strong>Ghi nhận kích thước file của readme.txt.</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bba37bcabedc43533fb1c84a35ede0745af44638/ntfs-6.png" alt="Readme-Size"></p></li><li><p>Bây giờ ẩn <strong>calc.exe</strong> bên trong <strong>readme.txt</strong> bằng cách nhập: <code>type c:\\trick\\calc.exe &gt; c:\\trick\\readme.txt:calc.exe</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bba37bcabedc43533fb1c84a35ede0745af44638/ntfs-7.png" alt="ntfs-4"></p></li><li><p>Nhập <strong>dir</strong> lại và ghi nhận kích thước file của <strong>readme.txt</strong> không thay đổi.</p></li><li><p>Quay lại <strong>c:\\trick</strong> và <strong>xóa calc.exe</strong>.</p></li></ol><h2 id="thuc-thi-ung-dung-bi-an" tabindex="-1">Thực thi Ứng dụng bị ẩn <a class="header-anchor" href="#thuc-thi-ung-dung-bi-an" aria-label="Permalink to &quot;Thực thi Ứng dụng bị ẩn&quot;">​</a></h2><ol start="9"><li><p>Tạo một symlink: <code>mklink backdoor.exe readme.txt:calc.exe</code></p></li><li><p>Thực thi backdoor.exe bằng cách nhập: <code>backdoor.exe</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e97b7c0d62642eaa8e502a1b51268913c67de3c3/NTFS-calc-5.png" alt="ntfs-5"></p></li></ol><p>Kẻ tấn công có thể ẩn file độc hại khỏi người dùng hợp pháp bằng cách sử dụng NTFS streams và thực thi chúng khi cần.</p>',15)]))}const u=e(s,[["render",i]]);export{m as __pageData,u as default};
